import { NextResponse } from 'next/server'
import { prisma } from '../../../lib/prisma'

// Vérifie si un créneau est occupé
async function checkCollision(staffId: string, start: Date, end: Date, excludeId?: string) {
  return await prisma.appointment.findFirst({
    where: {
      staffId: staffId,
      id: excludeId ? { not: excludeId } : undefined,
      AND: [
        { startTime: { lt: end } },
        { endTime: { gt: start } }
      ]
    }
  })
}

export async function GET() {
  try {
    const appointments = await prisma.appointment.findMany({
      include: {
        service: true, // Obligatoire pour récupérer la couleur
        customer: true
      },
    })

    type DbAppointment = { id: string; startTime: Date; endTime: Date; staffId: string; duration: number; serviceId: string; customerId: string; service?: { name?: string; color?: string }; customer?: { firstName?: string ; lastName?: string}; Note?: string | null }
    const apps = appointments as DbAppointment[]
    return NextResponse.json(apps.map((a) => ({
      id: a.id,

      // Le titre affiché dans l'agenda
      title: `${a.customer?.firstName || 'Client'}  ${a.customer?.lastName  || 'Client'}  —  ${a.service?.name || 'Service'}`,
      start: a.startTime.toISOString(),
      end: a.endTime.toISOString(),
      resourceId: a.staffId,
      color: a.service?.color || "#3788d8",
      extendedProps: {
        serviceId: a.serviceId,
        customerId: a.customerId,
        note: a.Note || null,
        duration: a.duration
      }
    })))
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 500 })
  }
}

export async function POST(request: Request) {
  try {
    const body = await request.json()
    const { start, end, duration, serviceId, customerId, staffId, note, force } = body

    // parse dates and basic validation
    const startDate = new Date(start)
    const endDate = new Date(end)
    if (!serviceId || !customerId) return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
    const dur = typeof duration === 'number' ? duration : parseInt(duration)
    if (Number.isNaN(dur)) return NextResponse.json({ error: 'Invalid duration' }, { status: 400 })
    if (Number.isNaN(startDate.getTime()) || Number.isNaN(endDate.getTime())) return NextResponse.json({ error: 'Invalid start or end date' }, { status: 400 })

    const firstOrg = await prisma.organization.findFirst()

    // Determine assigned staff: prefer provided staffId, else fallback to first staff in the org
    let assignedStaffId = staffId
    if (!assignedStaffId) {
      const fallback = await prisma.staff.findFirst({ where: { organizationId: firstOrg?.id } })
      assignedStaffId = fallback?.id
    }
    if (!assignedStaffId) return NextResponse.json({ error: 'No staff available to assign' }, { status: 400 })

    // Verify related records exist to avoid FK errors
    const [svc, cust, stf] = await Promise.all([
      prisma.service.findUnique({ where: { id: serviceId } }),
      prisma.customer.findUnique({ where: { id: customerId } }),
      prisma.staff.findUnique({ where: { id: assignedStaffId } }),
    ])
    if (!svc) return NextResponse.json({ error: 'Service not found' }, { status: 400 })
    if (!cust) return NextResponse.json({ error: 'Customer not found' }, { status: 400 })
    if (!stf) return NextResponse.json({ error: 'Staff not found' }, { status: 400 })

    // collision check using assignedStaffId
    if (!force) {
      try {
        const conflict = await checkCollision(assignedStaffId, startDate, endDate)
        if (conflict) return NextResponse.json({ error: 'Collision' }, { status: 409 })
      } catch (err) {
        console.error('Error during collision check (POST):', err)
        return NextResponse.json({ error: 'Error checking collision' }, { status: 500 })
      }
    }

    const appointment = await prisma.appointment.create({
      data: {
        startTime: startDate,
        endTime: endDate,
        duration: dur,
        Note: note || null,
        serviceId,
        customerId,
        staffId: assignedStaffId,
        organizationId: firstOrg?.id || "",
      }
    })
    return NextResponse.json(appointment)
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err)
    console.error('POST /api/appointments error:', message)
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

export async function PUT(request: Request) {
  try {
    const body = await request.json()
    console.error('PUT /api/appointments body:', JSON.stringify(body))
    const { id, start, end, duration, serviceId, customerId, staffId, note, force } = body

    if (!id) {
      console.error('PUT validation failed: missing id')
      return NextResponse.json({ error: 'Missing id' }, { status: 400 })
    }
    if (!serviceId || !customerId) {
      console.error('PUT validation failed: missing required fields', { serviceId, customerId })
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
    }
    const dur = typeof duration === 'number' ? duration : parseInt(duration)
    if (Number.isNaN(dur)) {
      console.error('PUT validation failed: invalid duration', { duration })
      return NextResponse.json({ error: 'Invalid duration' }, { status: 400 })
    }

    // validate dates
    const startDate = new Date(start)
    const endDate = new Date(end)
    if (Number.isNaN(startDate.getTime()) || Number.isNaN(endDate.getTime())) {
      console.error('PUT validation failed: invalid dates', { start, end })
      return NextResponse.json({ error: 'Invalid start or end date' }, { status: 400 })
    }

    // For updates: if staffId is provided, we'll update it; otherwise keep existing
    try {
      // ensure related records exist
      const [svc, cust] = await Promise.all([
        prisma.service.findUnique({ where: { id: serviceId } }),
        prisma.customer.findUnique({ where: { id: customerId } }),
      ])
      if (!svc) return NextResponse.json({ error: 'Service not found' }, { status: 400 })
      if (!cust) return NextResponse.json({ error: 'Customer not found' }, { status: 400 })

      // collision check: determine staff to check against
      let staffToCheck = staffId
      if (!staffToCheck) {
        // fetch current appointment to get its staff
        const existing = await prisma.appointment.findUnique({ where: { id } })
        if (!existing) return NextResponse.json({ error: 'Appointment not found' }, { status: 404 })
        staffToCheck = existing.staffId
      }
      if (!force) {
        const conflict = await checkCollision(staffToCheck, startDate, endDate, id)
        if (conflict) return NextResponse.json({ error: 'Collision' }, { status: 409 })
      }

      const dataToUpdate: any = {
        startTime: startDate,
        endTime: endDate,
        duration: dur,
        Note: note || null,
        serviceId,
        customerId,
      }
      if (staffId) dataToUpdate.staffId = staffId

      const updated = await prisma.appointment.update({ where: { id }, data: dataToUpdate })
      return NextResponse.json(updated)
    } catch (err) {
      // Prisma known error when record not found (P2025)
      const code = (err as any)?.code
      console.error('PUT /api/appointments caught error:', err)
      if (code === 'P2025') {
        return NextResponse.json({ error: 'Appointment not found' }, { status: 404 })
      }
      // For other Prisma errors (foreign key, etc.) return details for debugging
      return NextResponse.json({ error: String(err), code }, { status: 500 })
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err)
    console.error('PUT /api/appointments outer error:', message)
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

export async function DELETE(request: Request) {
  const { searchParams } = new URL(request.url)
  const id = searchParams.get('id')
  if (!id) return NextResponse.json({ error: "ID manquant" }, { status: 400 })
  await prisma.appointment.delete({ where: { id } })
  return NextResponse.json({ success: true })
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

// Vérifie si un créneau est occupé
async function checkCollision(staffId: string, start: Date, end: Date, excludeId?: string) {
  return await prisma.appointment.findFirst({
    where: {
      staffId: staffId,
      id: excludeId ? { not: excludeId } : undefined,
      AND: [
        { startTime: { lt: end } },
        { endTime: { gt: start } }
      ]
    }
  })
}

export async function GET(request: Request) {
  try {
    const url = new URL(request.url)
    const startParam = url.searchParams.get('start')
    const endParam = url.searchParams.get('end')

    const where: Record<string, unknown> = {}
    if (startParam) {
      const s = new Date(startParam)
      if (!Number.isNaN(s.getTime())) where.startTime = { gte: s }
    }
    if (endParam) {
      const e = new Date(endParam)
      if (!Number.isNaN(e.getTime())) where.endTime = where.endTime ? { ...where.endTime, lte: e } : { lte: e }
    }

    const appointments = await prisma.appointment.findMany({
      where: Object.keys(where).length ? where : undefined,
      include: {
        service: true, // Obligatoire pour récupérer la couleur et le prix
        customer: true
      },
    })

    type DbAppointment = { id: string; startTime: Date; endTime: Date; staffId: string; duration: number; serviceId: string; customerId: string; service?: { name?: string; color?: string; price?: number }; customer?: { firstName?: string ; lastName?: string}; Note?: string | null }
    const apps = appointments as DbAppointment[]
    return NextResponse.json(apps.map((a) => ({
      id: a.id,

      // Le titre affiché dans l'agenda
      title: `${a.customer?.firstName || 'Client'}  ${a.customer?.lastName  || 'Client'}  —  ${a.service?.name || 'Service'}`,
      start: a.startTime.toISOString(),
      end: a.endTime.toISOString(),
      resourceId: a.staffId,
      color: a.service?.color || "#3788d8",
      // include useful service info to compute CA client-side
      serviceName: a.service?.name || null,
      servicePrice: a.service?.price ?? null,
      extendedProps: {
        serviceId: a.serviceId,
        customerId: a.customerId,
        note: a.Note || null,
        duration: a.duration
      }
    })))
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 500 })
  }
}

