"use client"
import React, { useState, useEffect } from 'react';
import { Calendar, Users, TrendingUp, Clock, ChevronRight } from 'lucide-react';
import Link from 'next/link';

export default function Dashboard() {
  const [upcomingEvents, setUpcomingEvents] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        const res = await fetch('/api/appointments');
        if (res.ok) {
          const data = await res.json();

          const now = new Date();

          // FILTRE : Uniquement les RDV qui finissent après "maintenant"
          const filtered = data.filter((event: any) => {
            const eventEnd = new Date(event.end);
            return eventEnd > now;
          });

          // TRI : Du plus proche au plus lointain
          const sorted = filtered.sort((a: any, b: any) =>
              new Date(a.start).getTime() - new Date(b.start).getTime()
          );

          setUpcomingEvents(sorted);
        }
      } catch (err) {
        console.error("Erreur Dashboard:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  return (
      <div className="flex-1 p-8 space-y-8 overflow-y-auto bg-studio-bg">
        {/* Header */}
        <header className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-serif font-bold text-studio-text">Tableau de Bord</h1>
            <p className="text-studio-muted italic">Aperçu de votre activité à venir.</p>
          </div>
          <div className="text-right">
            <p className="text-sm font-bold uppercase tracking-widest text-studio-primary">
              {new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}
            </p>
          </div>
        </header>

        {/* Stats Rapides */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <StatCard title="Prochains RDV" value={upcomingEvents.length.toString()} icon={<Calendar size={20}/>} />
          <StatCard title="Nouveaux Clients" value="12" icon={<Users size={20}/>} />
          <StatCard title="CA Estimé" value="840€" icon={<TrendingUp size={20}/>} />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Liste des prochains RDV */}
          <div className="lg:col-span-2 studio-card p-8 bg-white min-h-[400px]">
            <div className="flex justify-between items-center mb-6">
              <h2 className="font-serif text-xl text-studio-text">Agenda à venir</h2>
              <Link href="/agenda" className="text-xs font-bold text-studio-primary hover:underline flex items-center gap-1">
                Voir tout l'agenda <ChevronRight size={14}/>
              </Link>
            </div>

            <div className="space-y-4">
              {loading ? (
                  <p className="text-studio-muted animate-pulse">Chargement des rendez-vous...</p>
              ) : upcomingEvents.length > 0 ? (
                  upcomingEvents.slice(0, 5).map((event) => (
                      <div key={event.id} className="flex items-center justify-between p-4 border border-studio-border rounded-2xl hover:bg-studio-bg/50 transition-colors">
                        <div className="flex items-center gap-4">
                          <div className="w-12 h-12 rounded-full bg-studio-accent flex flex-col items-center justify-center text-studio-primary border border-studio-primary/20">
                                            <span className="text-[10px] font-bold uppercase">
                                                {new Date(event.start).toLocaleDateString('fr-FR', { month: 'short' })}
                                            </span>
                            <span className="text-sm font-bold leading-none">
                                                {new Date(event.start).getDate()}
                                            </span>
                          </div>
                          <div>
                            <p className="font-bold text-sm text-studio-text">{event.title}</p>
                            <div className="flex items-center gap-2 text-xs text-studio-muted">
                              <Clock size={12} />
                              <span>{new Date(event.start).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                          </div>
                        </div>
                        <button className="p-2 hover:bg-white rounded-full transition-colors border border-transparent hover:border-studio-border">
                          <ChevronRight size={18} className="text-studio-muted" />
                        </button>
                      </div>
                  ))
              ) : (
                  <div className="text-center py-12">
                    <p className="text-studio-muted italic text-sm">Aucun rendez-vous de prévu pour le moment.</p>
                  </div>
              )}
            </div>
          </div>

          {/* Section Notes / Rappels */}
          <div className="space-y-6">
            <div className="studio-card p-8 bg-studio-primary text-white shadow-lg shadow-studio-primary/20">
              <h3 className="font-serif text-lg mb-2">Note du jour</h3>
              <p className="text-sm opacity-90 italic leading-relaxed">
                "Penser à vérifier les stocks de produits avant l'arrivée de Mme Durand à 14h."
              </p>
            </div>

            <div className="studio-card p-8 bg-white border-dashed border-2 border-studio-border flex flex-col items-center justify-center text-center py-12">
              <div className="w-12 h-12 bg-studio-bg rounded-full flex items-center justify-center text-studio-primary mb-4">
                <TrendingUp size={24} />
              </div>
              <p className="text-xs font-bold uppercase text-studio-muted mb-1">Objectif Hebdomadaire</p>
              <p className="text-xl font-serif text-studio-text">75% atteint</p>
            </div>
          </div>
        </div>
      </div>
  );
}

function StatCard({ title, value, icon }: { title: string, value: string, icon: React.ReactNode }) {
  return (
      <div className="studio-card p-6 bg-white hover:shadow-md transition-shadow">
        <div className="flex justify-between items-start mb-4">
          <div className="p-3 bg-studio-bg rounded-2xl text-studio-primary">
            {icon}
          </div>
        </div>
        <p className="text-[10px] font-bold text-studio-muted uppercase tracking-widest mb-1">{title}</p>
        <p className="text-2xl font-serif font-bold text-studio-text">{value}</p>
      </div>
  );
}

"use client"
import React, { useState, useEffect, useMemo } from 'react';
import { Calendar, Users, TrendingUp, Clock, ChevronRight } from 'lucide-react';
import Link from 'next/link';
import { startOfWeek, endOfWeek, format, differenceInCalendarDays } from 'date-fns'

export default function Dashboard() {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const controller = new AbortController()
    const fetchDashboardData = async () => {
      setLoading(true)
      try {
        const now = new Date()
        const start = startOfWeek(now, { weekStartsOn: 1 }) // semaine commençant lundi
        const end = endOfWeek(now, { weekStartsOn: 1 })
        const qs = `?start=${encodeURIComponent(start.toISOString())}&end=${encodeURIComponent(end.toISOString())}`
        const res = await fetch('/api/appointments' + qs, { signal: controller.signal })
        if (res.ok) {
          const data = await res.json()
          setAppointments(data)
        } else {
          console.error('Failed to load appointments for dashboard', res.status)
        }
      } catch (err) {
        if ((err as any)?.name === 'AbortError') return
        console.error("Erreur Dashboard:", err);
      } finally {
        setLoading(false)
      }
    }

    fetchDashboardData()
    return () => controller.abort()
  }, [])

  // --- Calculs memoized ---
  const weekMetrics = useMemo(() => {
    // CA : somme des servicePrice
    const totalCA = appointments.reduce((sum, a) => sum + (Number(a.servicePrice || 0)), 0)

    // Total duration in minutes
    const totalMinutes = appointments.reduce((sum, a) => sum + (Number(a.extendedProps?.duration || a.duration || 0)), 0)

    // Days in the week window
    const now = new Date()
    const start = startOfWeek(now, { weekStartsOn: 1 })
    const end = endOfWeek(now, { weekStartsOn: 1 })
    const days = differenceInCalendarDays(end, start) + 1
    const totalOpenMinutes = days * 12 * 60 // 12h par jour
    const occupancy = totalOpenMinutes > 0 ? (totalMinutes / totalOpenMinutes) * 100 : 0

    // Top services
    const counts: Record<string, number> = {}
    for (const a of appointments) {
      const name = a.serviceName || (a.extendedProps && a.extendedProps.serviceId) || 'Unknown'
      counts[name] = (counts[name] || 0) + 1
    }
    const topServices = Object.entries(counts).map(([name, count]) => ({ name, count })).sort((x, y) => y.count - x.count)

    // Unique customers
    const uniqueCustomers = new Set(appointments.map(a => a.extendedProps?.customerId || a.customerId)).size

    return {
      totalCA,
      occupancy,
      totalAppointments: appointments.length,
      uniqueCustomers,
      topServices,
    }
  }, [appointments])

  return (
      <div className="flex-1 p-8 space-y-8 overflow-y-auto" style={{ backgroundColor: '#FAF9F6' }}>
        {/* Header */}
        <header className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-serif font-bold text-studio-text">Tableau de Bord</h1>
            <p className="text-studio-muted italic">Aperçu de votre activité à venir.</p>
          </div>
          <div className="text-right">
            <p className="text-sm font-bold uppercase tracking-widest text-studio-primary">
              {new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}
            </p>
          </div>
        </header>

        {/* Stats Rapides */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="studio-card p-6 bg-white rounded-[2rem] shadow-sm">
            <div className="flex justify-between items-center mb-4">
              <div className="p-3 rounded-2xl" style={{ backgroundColor: '#FFF7F6' }}>
                <TrendingUp size={20} className="text-[#D4A3A1]" />
              </div>
            </div>
            <p className="text-[10px] font-bold text-studio-muted uppercase tracking-widest mb-1">CA cette semaine</p>
            <p className="text-2xl font-serif font-bold text-studio-text">{weekMetrics.totalCA.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR' })}</p>
          </div>

          <div className="studio-card p-6 bg-white rounded-[2rem] shadow-sm">
            <p className="text-[10px] font-bold text-studio-muted uppercase tracking-widest mb-2">Taux d'occupation</p>
            <div className="flex items-center gap-4">
              <div className="flex-1">
                <div className="w-full bg-[#F2F2F2] rounded-full h-3 overflow-hidden">
                  <div style={{ width: `${Math.min(100, Math.round(weekMetrics.occupancy))}%` }} className="h-3 bg-[#D4A3A1]" />
                </div>
                <p className="text-sm text-studio-muted mt-2">{weekMetrics.occupancy.toFixed(1)}%</p>
              </div>
            </div>
          </div>

          <div className="studio-card p-6 bg-white rounded-[2rem] shadow-sm">
            <div className="flex justify-between items-center mb-4">
              <div className="p-3 rounded-2xl" style={{ backgroundColor: '#FFF7F6' }}>
                <Users size={20} className="text-[#D4A3A1]" />
              </div>
            </div>
            <p className="text-[10px] font-bold text-studio-muted uppercase tracking-widest mb-1">Clients prévus</p>
            <p className="text-2xl font-serif font-bold text-studio-text">{weekMetrics.uniqueCustomers}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Graphiques / Prochains RDV compact */}
          <div className="lg:col-span-2 studio-card p-6 bg-white rounded-[2rem] shadow-sm min-h-[320px]">
            <div className="flex justify-between items-center mb-4">
              <h2 className="font-serif text-xl text-studio-text">Performance des services</h2>
              <Link href="/agenda" className="text-xs font-bold text-[#D4A3A1] hover:underline flex items-center gap-1">
                Voir tout l&apos;agenda <ChevronRight size={14}/>
              </Link>
            </div>

            <div className="space-y-3">
              {loading ? (
                <p className="text-studio-muted animate-pulse">Chargement des données...</p>
              ) : weekMetrics.topServices.length > 0 ? (
                weekMetrics.topServices.slice(0, 6).map((s) => {
                  const max = weekMetrics.topServices[0]?.count || 1
                  const width = Math.round((s.count / max) * 100)
                  return (
                    <div key={s.name} className="flex items-center gap-4">
                      <div className="w-1/3 text-sm text-studio-text">{s.name}</div>
                      <div className="flex-1 bg-[#F2F2F2] rounded-full h-4 overflow-hidden">
                        <div style={{ width: `${width}%` }} className="h-4 bg-[#D4A3A1]" />
                      </div>
                      <div className="w-12 text-right text-sm">{s.count}</div>
                    </div>
                  )
                })
              ) : (
                <div className="text-center py-8 text-studio-muted">Aucune donnée de services cette semaine.</div>
              )}
            </div>

            <div className="mt-6 border-t pt-4">
              <h3 className="font-serif text-lg mb-2">Prochains rendez-vous</h3>
              <div className="space-y-2">
                {loading ? (
                  <p className="text-studio-muted animate-pulse">Chargement...</p>
                ) : appointments.length > 0 ? (
                  appointments.slice(0, 6).map((event) => (
                    <div key={event.id} className="flex items-center justify-between p-3 border border-[#F2F2F2] rounded-xl">
                      <div>
                        <p className="font-bold text-sm">{event.title}</p>
                        <div className="text-xs text-studio-muted flex items-center gap-2"><Clock size={12}/> {new Date(event.start).toLocaleString('fr-FR', { hour: '2-digit', minute: '2-digit', day: 'numeric', month: 'short' })}</div>
                      </div>
                      <div className="text-sm text-studio-muted">{event.serviceName ? event.serviceName : ''}</div>
                    </div>
                  ))
                ) : (
                  <div className="text-center py-6 text-studio-muted">Aucun rendez-vous cette semaine.</div>
                )}
              </div>
            </div>
          </div>

          {/* Section Notes / KPI */}
          <div className="space-y-6">
            <div className="studio-card p-6 bg-white rounded-[2rem] shadow-sm">
              <h3 className="font-serif text-lg mb-2">Résumé</h3>
              <p className="text-sm text-studio-muted">RDV cette semaine: <strong>{weekMetrics.totalAppointments}</strong></p>
              <p className="text-sm text-studio-muted">CA estimé: <strong>{weekMetrics.totalCA.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR' })}</strong></p>
              <p className="text-sm text-studio-muted">Taux occupation: <strong>{weekMetrics.occupancy.toFixed(1)}%</strong></p>
            </div>

            <div className="studio-card p-6 bg-white rounded-[2rem] shadow-sm">
              <h3 className="font-serif text-lg mb-2">Objectif Hebdomadaire</h3>
              <p className="text-sm opacity-90 italic leading-relaxed text-studio-muted">Viser à saturer 75% des créneaux réservables.</p>
            </div>
          </div>
        </div>
      </div>
  );
}

function StatCard({ title, value, icon }: { title: string, value: string, icon: React.ReactNode }) {
  return (
      <div className="studio-card p-6 bg-white hover:shadow-md transition-shadow">
        <div className="flex justify-between items-start mb-4">
          <div className="p-3 bg-studio-bg rounded-2xl text-studio-primary">
            {icon}
          </div>
        </div>
        <p className="text-[10px] font-bold text-studio-muted uppercase tracking-widest mb-1">{title}</p>
        <p className="text-2xl font-serif font-bold text-studio-text">{value}</p>
      </div>
  );
}

"use client"
import React, { useState, useEffect, useCallback } from 'react';
import FullCalendar from '@fullcalendar/react';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';
import dayGridPlugin from '@fullcalendar/daygrid';
import frLocale from '@fullcalendar/core/locales/fr';
import type { DateSelectArg, EventClickArg, EventContentArg, EventMountArg } from '@fullcalendar/core';
import AppointmentModal from './calendar/AppointmentModal';

// Imports Tippy pour les bulles d'infos
import tippy from 'tippy.js';
import 'tippy.js/dist/tippy.css';
import 'tippy.js/animations/shift-away.css';

export default function AppointmentScheduler() {
    // --- INTERFACES & ÉTATS ---
    interface CalEvent {
        id: string;
        title?: string;
        start?: string;
        end?: string;
        extendedProps?: Record<string, any>;
        color?: string
    }

    const [events, setEvents] = useState<CalEvent[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedRange, setSelectedRange] = useState<DateSelectArg | null>(null);
    const [editingEvent, setEditingEvent] = useState<any | null>(null);

    const [customers, setCustomers] = useState([]);
    const [services, setServices] = useState([]);
    const [staffs, setStaffs] = useState([]);

    // --- CHARGEMENT DES DONNÉES ---
    const fetchAppointments = useCallback(async (signal?: AbortSignal) => {
        try {
            const res = await fetch('/api/appointments', { signal });
            if (res.ok) {
                const data = await res.json();
                if (!signal || !signal.aborted) setEvents(data);
            }
        } catch (err) { console.error("Erreur RDV:", err); }
    }, []);

    useEffect(() => {
        const controller = new AbortController();
        const signal = controller.signal;

        const loadResources = async () => {
            await fetchAppointments(signal);
            try {
                const [resC, resS, resT] = await Promise.all([
                    fetch('/api/customers', { signal }),
                    fetch('/api/services', { signal }),
                    fetch('/api/staff', { signal })
                ]);
                if (!signal.aborted) {
                    if (resC.ok) setCustomers(await resC.json());
                    if (resS.ok) setServices(await resS.json());
                    if (resT.ok) setStaffs(await resT.json());
                }
            } catch (err) { console.error("Erreur ressources:", err); }
        };

        loadResources();
        return () => controller.abort();
    }, [fetchAppointments]);

    return (
        <div className="flex-1 flex flex-col h-full w-full p-6 min-h-0">
            <div className="studio-card flex-1 p-6 min-h-0 overflow-hidden bg-white rounded-[2rem] border border-studio-border shadow-sm">
                <FullCalendar
                    plugins={[timeGridPlugin, interactionPlugin, dayGridPlugin]}
                    initialView="timeGridWeek"
                    height="100%"
                    contentHeight="100%"
                    expandRows={true}
                    events={events}
                    locale="fr"
                    locales={[frLocale]}
                    selectable={true}
                    nowIndicator={true}
                    slotMinTime="08:00:00"
                    slotMaxTime="20:00:00"
                    allDaySlot={false}
                    headerToolbar={{
                        left: 'prev,next today',
                        center: 'title',
                        right: 'timeGridDay,timeGridWeek'
                    }}

                    // --- 1. RENDU DES CASES (MINI) ---
                    eventContent={(info: EventContentArg) => (
                        <div className="p-1 leading-tight overflow-hidden">
                            <p className="font-bold text-[10px] uppercase truncate text-studio-text">
                                {info.event.title}
                            </p>
                            <p className="text-[9px] text-studio-text/70">
                                {info.timeText}
                            </p>
                        </div>
                    )}

                    // --- 2. BULLE D'INFOS (TIPPY) ---
                    eventDidMount={(info: EventMountArg) => {
                        const props = info.event.extendedProps;
                        tippy(info.el, {
                            content: `
                                <div style="color: #2D2424;">
                                    <p style="color: #D4A3A1; font-weight: 800; font-size: 10px; text-transform: uppercase; margin: 0 0 4px 0;">Détails du RDV</p>
                                    <p style="font-weight: 700; font-size: 14px; margin: 0;">${info.event.title}</p>
                                    <div style="margin-top: 8px; display: flex; flex-direction: column; gap: 2px;">
                                        <p style="font-size: 11px; margin: 0;">⏰ <b>${info.timeText}</b></p>
                                        ${props.customerName ? `<p style="font-size: 11px; margin: 0;"> ${props.customerName} </p>` : ''}
                                        ${props.serviceName ? `<p style="font-size: 11px; color: #D4A3A1; font-style: italic; margin-top: 4px;">✨ ${props.serviceName}</p>` : ''}
                                        ${props.price ? `<p style="font-size: 11px; font-weight: bold; margin-top: 2px;"> ${props.price}</p>` : ''}
                                    </div>
                                </div>
                            `,
                            allowHTML: true,
                            theme: 'studio-light',
                            placement: 'top',
                            animation: 'shift-away',
                            interactive: true,
                            appendTo: () => document.body,
                        });
                    }}

                    // --- 3. ACTIONS (CLIC & SÉLECTION) ---
                    select={(info: DateSelectArg) => {
                        setSelectedRange(info);
                        setEditingEvent(null);
                        setIsModalOpen(true);
                    }}

                    eventClick={(info: EventClickArg) => {
                        // FIX CRITIQUE : On fusionne les infos de base et les extendedProps
                        const eventData = {
                            id: info.event.id,
                            title: info.event.title,
                            start: info.event.start?.toISOString(),
                            end: info.event.end?.toISOString(),
                            ...info.event.extendedProps // Récupère customerId, serviceId, etc.
                        };
                        setEditingEvent(eventData);
                        setSelectedRange(null);
                        setIsModalOpen(true);
                    }}
                />
            </div>

            {/* MODALE DE RENDEZ-VOUS */}
            <AppointmentModal
                isOpen={isModalOpen}
                onClose={() => {
                    setIsModalOpen(false);
                    fetchAppointments(); // Rafraîchir après fermeture
                }}
                selectedRange={selectedRange}
                initialData={editingEvent}
                customers={customers}
                services={services}
                staffs={staffs}
            />
        </div>
    );
}

"use client"
import React, { useState, useEffect, useCallback } from 'react';
import FullCalendar from '@fullcalendar/react';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';
import dayGridPlugin from '@fullcalendar/daygrid';
import frLocale from '@fullcalendar/core/locales/fr';
import type { DateSelectArg, EventClickArg, EventContentArg, EventMountArg } from '@fullcalendar/core';
import AppointmentModal from './calendar/AppointmentModal';

// Imports Tippy pour les bulles d'infos
import tippy from 'tippy.js';
import 'tippy.js/dist/tippy.css';
import 'tippy.js/animations/shift-away.css';

export default function AppointmentScheduler() {
    // --- INTERFACES & ÉTATS ---
    interface CalEvent {
        id: string;
        title?: string;
        start?: string;
        end?: string;
        extendedProps?: Record<string, unknown>;
        color?: string
    }

    const [events, setEvents] = useState<CalEvent[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedRange, setSelectedRange] = useState<DateSelectArg | null>(null);
    const [editingEvent, setEditingEvent] = useState<Record<string, unknown> | null>(null);

    // avoid hydration mismatches from FullCalendar internal IDs: render it only after client mount
    const [mounted, setMounted] = useState(false);
    useEffect(() => { setMounted(true); }, []);

    const [customers, setCustomers] = useState([]);
    const [services, setServices] = useState([]);
    const [staffs, setStaffs] = useState([]);

    // --- CHARGEMENT DES DONNÉES ---
    const fetchAppointments = useCallback(async (signal?: AbortSignal) => {
        try {
            const res = await fetch('/api/appointments', { signal });
            if (res.ok) {
                const data = await res.json();
                if (!signal || !signal.aborted) setEvents(data);
            }
        } catch (err) {
            if (isAbortError(err)) return
            console.error("Erreur RDV:", err);
        }
    }, []);

    function isAbortError(err: unknown): boolean {
        return typeof err === 'object' && err !== null && 'name' in err && (err as { name?: unknown }).name === 'AbortError'
    }

    useEffect(() => {
        const controller = new AbortController();
        const signal = controller.signal;

        const loadResources = async () => {
            await fetchAppointments(signal);
            try {
                const [resC, resS, resT] = await Promise.all([
                    fetch('/api/customers', { signal }),
                    fetch('/api/services', { signal }),
                    fetch('/api/staff', { signal })
                ]);
                if (!signal.aborted) {
                    if (resC.ok) setCustomers(await resC.json());
                    if (resS.ok) setServices(await resS.json());
                    if (resT.ok) setStaffs(await resT.json());
                }
            } catch (err) {
                if (isAbortError(err)) return
                console.error("Erreur ressources:", err);
            }
        };

        loadResources();
        return () => controller.abort();
    }, [fetchAppointments]);

    return (
        <div className="flex-1 flex flex-col h-full w-full p-6 min-h-0">
            <div className="studio-card flex-1 p-6 min-h-0 overflow-hidden bg-white rounded-[2rem] border border-studio-border shadow-sm">
                {mounted ? (
                    <FullCalendar
                        plugins={[timeGridPlugin, interactionPlugin, dayGridPlugin]}
                        initialView="timeGridWeek"
                        height="100%"
                        contentHeight="100%"
                        expandRows={true}
                        events={events}
                        locale="fr"
                        locales={[frLocale]}
                        selectable={true}
                        nowIndicator={true}
                        slotMinTime="08:00:00"
                        slotMaxTime="20:00:00"
                        allDaySlot={false}
                        headerToolbar={{
                            left: 'prev,next today',
                            center: 'title',
                            right: 'timeGridDay,timeGridWeek'
                        }}

                        // --- 1. RENDU DES CASES (MINI) ---
                        eventContent={(info: EventContentArg) => (
                            <div className="p-1 leading-tight overflow-hidden">
                                <p className="font-bold text-[10px] uppercase truncate text-studio-text">
                                    {info.event.title}
                                </p>
                                <p className="text-[9px] text-studio-text/70">
                                    {info.timeText}
                                </p>
                            </div>
                        )}

                        // --- 2. BULLE D'INFOS (TIPPY) ---
                        eventDidMount={(info: EventMountArg) => {
                            const props = info.event.extendedProps;
                            tippy(info.el, {
                                content: `
                                    <div style="color: #2D2424;">
                                        <p style="color: #D4A3A1; font-weight: 800; font-size: 10px; text-transform: uppercase; margin: 0 0 4px 0;">Détails du RDV</p>
                                        <p style="font-weight: 700; font-size: 14px; margin: 0;">${info.event.title}</p>
                                        <div style="margin-top: 8px; display: flex; flex-direction: column; gap: 2px;">
                                            <p style="font-size: 11px; margin: 0;">⏰ <b>${info.timeText}</b></p>
                                            ${props.customerName ? `<p style="font-size: 11px; margin: 0;"> ${props.customerName} </p>` : ''}
                                            ${props.serviceName ? `<p style="font-size: 11px; color: #D4A3A1; font-style: italic; margin-top: 4px;">✨ ${props.serviceName}</p>` : ''}
                                            ${props.price ? `<p style="font-size: 11px; font-weight: bold; margin-top: 2px;"> ${props.price}</p>` : ''}
                                        </div>
                                    </div>
                                `,
                                allowHTML: true,
                                theme: 'studio-light',
                                placement: 'top',
                                animation: 'shift-away',
                                interactive: true,
                                appendTo: () => document.body,
                            });
                        }}

                        // --- 3. ACTIONS (CLIC & SÉLECTION) ---
                        select={(info: DateSelectArg) => {
                            setSelectedRange(info);
                            setEditingEvent(null);
                            setIsModalOpen(true);
                        }}

                        eventClick={(info: EventClickArg) => {
                            // FIX CRITIQUE : On fusionne les infos de base et les extendedProps
                            const eventData = {
                                id: info.event.id,
                                title: info.event.title,
                                start: info.event.start?.toISOString(),
                                end: info.event.end?.toISOString(),
                                ...info.event.extendedProps // Récupère customerId, serviceId, etc.
                            };
                            setEditingEvent(eventData);
                            setSelectedRange(null);
                            setIsModalOpen(true);
                        }}
                    />
                ) : (
                    // lightweight placeholder matching approximate structure so React can hydrate cleanly
                    <div className="h-full w-full" aria-hidden="true" />
                )}
            </div>

            {/* MODALE DE RENDEZ-VOUS */}
            <AppointmentModal
                isOpen={isModalOpen}
                onClose={() => {
                    setIsModalOpen(false);
                    setSelectedRange(null);
                }}
                onSuccess={async () => { await fetchAppointments(); }}
                selectedRange={selectedRange}
                initialData={editingEvent}
                customers={customers}
                services={services}
                staffs={staffs}
            />
        </div>
    );
}

"use client"

import React, { useState, useEffect } from 'react'
import { format, addMinutes, isValid, parse, differenceInMinutes } from "date-fns"
import { Trash2, AlertTriangle, Zap } from "lucide-react"
import BaseModal from "@/components/ui/BaseModal"
import { CustomerPicker } from "./CustomerPicker"
import type { Customer as CustomerType, Service as ServiceType, Staff as StaffType } from '@/types/models'

type Range = { start: Date; end: Date }
type InitialData = Partial<{
    id: string;
    title: string;
    start: string;
    end: string;
    serviceId: string;
    customerId: string;
    staffId: string;
    duration: number;
    note: string;
    extendedProps?: Record<string, any>
}>

interface AppointmentModalProps {
    isOpen: boolean
    onClose: () => void
    selectedRange?: Range | null
    initialData?: InitialData | null
    services?: ServiceType[]
    staffs?: StaffType[]
    customers?: CustomerType[]
}

export default function AppointmentModal({
                                             isOpen,
                                             onClose,
                                             selectedRange,
                                             initialData = null,
                                             services = [],
                                             staffs = [],
                                             customers = []
                                         }: AppointmentModalProps) {
    // --- ÉTATS DU FORMULAIRE ---
    const [selectedCustomer, setSelectedCustomer] = useState<CustomerType | null>(null)
    const [serviceId, setServiceId] = useState("")
    const [note, setNote] = useState("")
    const [startTime, setStartTime] = useState("")
    const [duration, setDuration] = useState<number>(30)
    const [isSaving, setIsSaving] = useState(false)

    // --- ÉTATS COLLISIONS ---
    const [collision, setCollision] = useState(false)
    const [forceSave, setForceSave] = useState(false)

    // --- SYNCHRONISATION (INITIALISATION) ---
    useEffect(() => {
        if (!isOpen) return

        setCollision(false)
        setForceSave(false)

            if (initialData) {
            // MODE ÉDITION
            const start = initialData.start ? new Date(initialData.start) : null
            const d = initialData.duration || initialData.extendedProps?.duration || 30
            const startStr = start && isValid(start) ? format(start, "HH:mm") : ""
            const svcId = initialData.serviceId || initialData.extendedProps?.serviceId || ""

            // Récupération de la note (soit à la racine, soit dans extendedProps)
            const noteVal = initialData.note || initialData.extendedProps?.note || ""

            const cId = initialData.customerId || initialData.extendedProps?.customerId
            const selected = customers.find(c => c.id === cId) || null

            // On utilise un timeout de 0 pour laisser le temps au DOM de se stabiliser
            setTimeout(() => {
                setDuration(Number(d))
                setStartTime(startStr)
                setServiceId(svcId)
                setNote(noteVal)
                setSelectedCustomer(selected)
            }, 0)
        } else if (selectedRange) {
            // MODE CRÉATION
            const start = new Date(selectedRange.start)
            const end = new Date(selectedRange.end)

            setStartTime(isValid(start) ? format(start, "HH:mm") : "")
            const diff = differenceInMinutes(end, start)
            setDuration(diff > 0 ? diff : 30)
            setNote("")
            setSelectedCustomer(null)
            setServiceId("")
        }
        // IMPORTANT : On ne met PAS 'note' dans les dépendances pour pouvoir taper au clavier sans reset
    }, [isOpen, initialData, selectedRange, customers, staffs])

    // --- LOGIQUE MÉTIER ---
    const getEndTimeLabel = () => {
        if (!startTime) return "--:--"
        try {
            const date = parse(startTime, "HH:mm", new Date())
            return format(addMinutes(date, duration), "HH:mm")
        } catch { return "--:--" }
    }

    const handleServiceChange = (id: string) => {
        setServiceId(id)
        setCollision(false)
        const foundService = services.find((s) => s.id === id)
        if (foundService) {
            const newDur = foundService.durationMinutes || 30
            setDuration(Number(newDur))
        }
    }

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!selectedCustomer || !serviceId) return

        setIsSaving(true)
        const baseDate = new Date(initialData?.start || selectedRange?.start || new Date())
        const [h, m] = startTime.split(':').map(Number)
        baseDate.setHours(h, m, 0, 0)

        try {
            const res = await fetch('/api/appointments', {
                method: initialData?.id ? 'PUT' : 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    id: initialData?.id,
                    start: baseDate.toISOString(),
                    end: addMinutes(baseDate, duration).toISOString(),
                    duration: Number(duration),
                    customerId: selectedCustomer.id,
                    serviceId,
                    note: note, // Envoi de la note à l'API
                    force: forceSave,
                }),
            })

            if (res.ok) {
                onClose()
                window.location.reload()
            } else {
                let payload: any = null
                try { payload = await res.json() } catch (e) { /* ignore */ }
                console.error('Save failed', res.status, payload)
                if (res.status === 409) {
                    setCollision(true)
                    setIsSaving(false)
                } else {
                    const msg = payload?.error || payload || `HTTP ${res.status}`
                    // show a user-friendly alert and keep modal open for fixes
                    alert('Erreur serveur: ' + msg)
                    setIsSaving(false)
                }
            }
        } catch (error) {
            console.error(error)
            setIsSaving(false)
        }
    }

    const handleDelete = async () => {
        if (!initialData?.id || !confirm("Supprimer ce rendez-vous ?")) return
        await fetch(`/api/appointments?id=${initialData.id}`, { method: 'DELETE' })
        window.location.reload()
    }

    const found = services.find(s => s.id === serviceId)
    const currentServiceColor = (found && found.color) ? found.color : "#CBD5E1"

    if (!isOpen) return null

    return (
        <BaseModal isOpen={isOpen} onClose={onClose} title={initialData?.id ? "Modifier le RDV" : "Nouveau RDV"}>
            <form onSubmit={handleSave} className="flex flex-col gap-5">

                {/* SECTION CLIENT */}
                <div>
                    <label className="text-[11px] font-bold text-studio-muted mb-2 block uppercase">Client</label>
                    <CustomerPicker
                        customers={customers}
                        onSelect={(id: string) => setSelectedCustomer(customers.find(c => c.id === id) || null)}
                        selectedId={selectedCustomer?.id}
                    />
                </div>

                {/* SECTION TEMPS */}
                <div className="grid grid-cols-2 gap-3 p-4 bg-[#F8FAFC] rounded-2xl border border-[#F1F5F9]">
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 flex items-center gap-1 uppercase">Début</label>
                        <input
                            type="time"
                            value={startTime}
                            onChange={(e) => {setStartTime(e.target.value); setCollision(false)}}
                            className="w-full border-none bg-transparent text-lg font-bold outline-none text-slate-800"
                        />
                    </div>
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 uppercase">Durée (min)</label>
                        <input
                            type="number"
                            step="5"
                            value={duration}
                            onChange={(e) => {setDuration(e.target.valueAsNumber || 0); setCollision(false)}}
                            className="w-full border-none bg-transparent text-lg font-bold outline-none text-slate-800"
                        />
                    </div>
                    <div className="col-span-2 text-[10px] text-slate-400 border-t border-slate-200 pt-2 mt-1">
                        Fin prévue à : <strong className="text-slate-600">{getEndTimeLabel()}</strong>
                    </div>
                </div>

                {/* SECTION SERVICE ET NOTE */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div className="flex flex-col gap-1.5">
                        <label className="text-[10px] font-bold text-studio-muted flex items-center gap-1.5 uppercase">
                            Service
                            {serviceId && (
                                <span className="w-2.5 h-2.5 rounded-full border border-black/10" style={{ backgroundColor: currentServiceColor }} />
                            )}
                        </label>
                        <select
                            value={serviceId}
                            onChange={(e) => handleServiceChange(e.target.value)}
                            className="p-2.5 rounded-xl border border-slate-200 outline-none bg-white text-sm"
                        >
                            <option value="">Choisir un service...</option>
                            {services.map((s) => (
                                <option key={s.id} value={s.id}>{s.name} ({s.durationMinutes} min)</option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col gap-1.5">
                        <label className="text-[10px] font-bold text-studio-muted uppercase">Note</label>
                        <input
                            type="text"
                            placeholder="Ex: Cheveux épais, café noir..."
                            value={note}
                            onChange={(e) => setNote(e.target.value)}
                            className="p-2.5 rounded-xl border border-slate-200 outline-none bg-white text-sm text-slate-800"
                        />
                    </div>
                </div>

                {/* ACTIONS */}
                <div className="flex justify-between items-center mt-2">
                    {initialData?.id && (
                        <button
                            type="button"
                            onClick={handleDelete}
                            className="text-red-500 text-[11px] font-bold flex items-center gap-1.5 hover:opacity-80 transition-opacity"
                        >
                            <Trash2 size={14} /> SUPPRIMER
                        </button>
                    )}
                    <div className="flex gap-2 ml-auto">
                        <button type="button" onClick={onClose} className="px-5 py-2 text-slate-400 font-bold text-sm">
                            ANNULER
                        </button>
                        <button
                            type="submit"
                            disabled={isSaving}
                            className="px-7 py-3 bg-studio-primary text-white rounded-full font-bold text-sm flex items-center gap-2 shadow-lg shadow-studio-primary/20 disabled:opacity-50"
                        >
                            {isSaving ? "..." : <><Zap size={14} /> CONFIRMER</>}
                        </button>
                    </div>
                </div>
            </form>
        </BaseModal>
    )
}

"use client"

import React, { useState, useEffect } from 'react'
import { format, addMinutes, isValid, parse, differenceInMinutes } from "date-fns"
import { Trash2, AlertTriangle, Zap } from "lucide-react"
import BaseModal from "@/components/ui/BaseModal"
import { CustomerPicker } from "./CustomerPicker"
import type { Customer as CustomerType, Service as ServiceType, Staff as StaffType } from '@/types/models'

type Range = { start: Date; end: Date }
type InitialData = Partial<{
    id: string;
    title: string;
    start: string;
    end: string;
    serviceId: string;
    customerId: string;
    staffId: string;
    duration: number;
    note: string;
    extendedProps?: Record<string, unknown>
}>

interface AppointmentModalProps {
    isOpen: boolean
    onClose: () => void
    onSuccess: () => Promise<void>
    selectedRange?: Range | null
    initialData?: InitialData | null
    services?: ServiceType[]
    staffs?: StaffType[]
    customers?: CustomerType[]
}

export default function AppointmentModal({
                                             isOpen,
                                             onClose,
                                             onSuccess,
                                             selectedRange,
                                             initialData = null,
                                             services = [],
                                             staffs = [],
                                             customers = []
                                         }: AppointmentModalProps) {
    // --- ÉTATS DU FORMULAIRE ---
    // form state initializers created below so we can derive initial values from props
    const [isSaving, setIsSaving] = useState(false)

    // --- ÉTATS COLLISIONS ---
    const [collision, setCollision] = useState(false)
    const [forceSave, setForceSave] = useState(false)

    // Initialize local state with sensible defaults; we'll populate them when the modal opens
    const [selectedCustomerState, setSelectedCustomerState] = useState<CustomerType | null>(null)
    const [serviceIdState, setServiceIdState] = useState("")
    const [noteState, setNoteState] = useState("")
    const [startTimeState, setStartTimeState] = useState("")
    const [durationState, setDurationState] = useState<number>(30)

    // When the modal opens (or when initialData/selectedRange/customers change), initialize form state
    useEffect(() => {
        if (!isOpen) return

        // compute initial values from initialData if editing
        if (initialData) {
            const start = initialData.start ? new Date(initialData.start) : null
            const d = initialData.duration || initialData.extendedProps?.duration || 30
            const startStr = start && isValid(start) ? format(start, "HH:mm") : ""
            const svcId = initialData.serviceId || initialData.extendedProps?.serviceId || ""
            const noteVal = initialData.note || initialData.extendedProps?.note || ""
            const cId = initialData.customerId || initialData.extendedProps?.customerId
            const selected = customers.find((c: any) => c.id === cId) || null

            setSelectedCustomerState(selected)
            setServiceIdState(svcId)
            setNoteState(noteVal)
            setStartTimeState(startStr)
            setDurationState(Number(d))
            return
        }

        // otherwise, if a range was selected in the calendar, use that
        if (selectedRange) {
            // selectedRange may come from FullCalendar DateSelectArg and contain Date objects
            const start = new Date((selectedRange as any).start)
            const end = new Date((selectedRange as any).end)
            const startStr = isValid(start) ? format(start, "HH:mm") : ""
            const diff = differenceInMinutes(end, start)

            setSelectedCustomerState(null)
            setServiceIdState("")
            setNoteState("")
            setStartTimeState(startStr)
            setDurationState(diff > 0 ? diff : 30)
            return
        }

        // default empty form
        setSelectedCustomerState(null)
        setServiceIdState("")
        setNoteState("")
        setStartTimeState("")
        setDurationState(30)
    }, [isOpen, initialData, selectedRange, customers])

    // Keep using the old state names for downstream code compatibility by aliasing
    const selectedCustomer = selectedCustomerState
    const setSelectedCustomer = setSelectedCustomerState
    const serviceId = serviceIdState
    const setServiceId = setServiceIdState
    const note = noteState
    const setNote = setNoteState
    const startTime = startTimeState
    const setStartTime = setStartTimeState
    const duration = durationState
    const setDuration = setDurationState

    // --- CONTRAINTES HORAIRES ---
    const HORAIRE_OUVERTURE = "08:00"
    const HORAIRE_FERMETURE = "20:00"

    function isTimeValid(time: string, durationMinutes: number) {
        if (!time) return false
        try {
            const start = parse(time, "HH:mm", new Date())
            const end = addMinutes(start, durationMinutes)
            const open = parse(HORAIRE_OUVERTURE, "HH:mm", new Date())
            const close = parse(HORAIRE_FERMETURE, "HH:mm", new Date())
            return start >= open && end <= close
        } catch {
            return false
        }
    }

    const isTimeOutOfBounds = !isTimeValid(startTime, duration)

    // Validation du formulaire (champs obligatoires + horaires + durée)
    const isFormInvalid = !selectedCustomer || !serviceId || isTimeOutOfBounds || (Number(duration) <= 0)

    /* reset collision/force flags when modal opens (intentionally setting state in effect) */
    /* eslint-disable react-hooks/set-state-in-effect */
    useEffect(() => {
        if (!isOpen) return
        setTimeout(() => {
            setCollision(false)
            setForceSave(false)
        }, 0)
    }, [isOpen])
    /* eslint-enable react-hooks/set-state-in-effect */

            // avoid calling setState after unmount while awaiting onSuccess
            const mountedRef = React.useRef(true)
            useEffect(() => {
                mountedRef.current = true
                return () => { mountedRef.current = false }
            }, [])

    // --- LOGIQUE MÉTIER ---
    const getEndTimeLabel = () => {
        if (!startTime) return "--:--"
        try {
            const date = parse(startTime, "HH:mm", new Date())
            return format(addMinutes(date, duration), "HH:mm")
        } catch { return "--:--" }
    }

    const handleServiceChange = (id: string) => {
        setServiceId(id)
        setCollision(false)
        const foundService = services.find((s) => s.id === id)
        if (foundService) {
            const newDur = foundService.durationMinutes || 30
            setDuration(Number(newDur))
        }
    }

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault()
        // sécurité côté client: empêcher l'envoi si le formulaire est invalide
        if (isFormInvalid) return

        setIsSaving(true)
        const baseDate = new Date(initialData?.start || selectedRange?.start || new Date())
        const [h, m] = startTime.split(':').map(Number)
        baseDate.setHours(h, m, 0, 0)

        try {
            const res = await fetch('/api/appointments', {
                method: initialData?.id ? 'PUT' : 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    id: initialData?.id,
                    start: baseDate.toISOString(),
                    end: addMinutes(baseDate, duration).toISOString(),
                    duration: Number(duration),
                    customerId: selectedCustomer.id,
                    serviceId,
                    note: note, // Envoi de la note à l'API
                    force: forceSave,
                }),
            })

            if (res.ok) {
                // Close the modal immediately, then refresh parent data asynchronously
                try {
                    onClose()
                    await onSuccess()
                } catch (err) {
                    console.error('onSuccess failed:', err)
                    // If the modal is still mounted, show an error and keep saving state
                    if (mountedRef.current) {
                        alert('Erreur lors de la mise à jour de l\'agenda.')
                    }
                } finally {
                    if (mountedRef.current) setIsSaving(false)
                }
            } else {
                let payload: any = null
                try { payload = await res.json() } catch (e) { /* ignore */ }
                console.error('Save failed', res.status, payload)
                if (res.status === 409) {
                    setCollision(true)
                    setIsSaving(false)
                } else {
                    const msg = payload?.error || payload || `HTTP ${res.status}`
                    // show a user-friendly alert and keep modal open for fixes
                    alert('Erreur serveur: ' + msg)
                    setIsSaving(false)
                }
            }
        } catch (error) {
            console.error(error)
            setIsSaving(false)
        }
    }

    const handleDelete = async () => {
        if (!initialData?.id || !confirm("Supprimer ce rendez-vous ?")) return
        setIsSaving(true)
        try {
            const res = await fetch(`/api/appointments?id=${initialData.id}`, { method: 'DELETE' })
            if (res.ok) {
                try {
                    onClose()
                    await onSuccess()
                } catch (err) {
                    console.error('onSuccess failed (delete):', err)
                    if (mountedRef.current) alert('Erreur lors de la mise à jour de l\'agenda.')
                } finally {
                    if (mountedRef.current) setIsSaving(false)
                }
            } else {
                let payload: any = null
                try { payload = await res.json() } catch (e) { /* ignore */ }
                alert('Erreur suppression: ' + (payload?.error || `HTTP ${res.status}`))
                if (mountedRef.current) setIsSaving(false)
            }
        } catch (err) {
            console.error('Delete error:', err)
            if (mountedRef.current) setIsSaving(false)
        }
    }

    const found = services.find(s => s.id === serviceId)
    const currentServiceColor = (found && found.color) ? found.color : "#CBD5E1"

    if (!isOpen) return null

    return (
        <BaseModal isOpen={isOpen} onClose={onClose} title={initialData?.id ? "Modifier le RDV" : "Nouveau RDV"}>
            <form onSubmit={handleSave} className="flex flex-col gap-5">

                {/* SECTION CLIENT */}
                <div>
                    <label className="text-[11px] font-bold text-studio-muted mb-2 block uppercase">Client</label>
                    <CustomerPicker
                        customers={customers}
                        onSelect={(id: string) => setSelectedCustomer(customers.find(c => c.id === id) || null)}
                        selectedId={selectedCustomer?.id}
                    />
                </div>

                {/* SECTION TEMPS */}
                <div className="grid grid-cols-2 gap-3 p-4 bg-[#F8FAFC] rounded-2xl border border-[#F1F5F9]">
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 flex items-center gap-1 uppercase">Début</label>
                        <input
                            type="time"
                            value={startTime}
                            onChange={(e) => {setStartTime(e.target.value); setCollision(false)}}
                            className="w-full border-none bg-transparent text-lg font-bold outline-none text-slate-800"
                        />
                        {isTimeOutOfBounds && (
                            <div className="text-[12px] text-red-500 mt-1">L'heure doit être comprise entre {HORAIRE_OUVERTURE} et {HORAIRE_FERMETURE}.</div>
                        )}
                    </div>
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 uppercase">Durée (min)</label>
                        <input
                            type="number"
                            step="5"
                            value={duration}
                            onChange={(e) => {setDuration(e.target.valueAsNumber || 0); setCollision(false)}}
                            className="w-full border-none bg-transparent text-lg font-bold outline-none text-slate-800"
                        />
                    </div>
                    <div className="col-span-2 text-[10px] text-slate-400 border-t border-slate-200 pt-2 mt-1">
                        Fin prévue à : <strong className="text-slate-600">{getEndTimeLabel()}</strong>
                    </div>
                </div>

                {/* SECTION SERVICE ET NOTE */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div className="flex flex-col gap-1.5">
                        <label className="text-[10px] font-bold text-studio-muted flex items-center gap-1.5 uppercase">
                            Service
                            {serviceId && (
                                <span className="w-2.5 h-2.5 rounded-full border border-black/10" style={{ backgroundColor: currentServiceColor }} />
                            )}
                        </label>
                        <select
                            value={serviceId}
                            onChange={(e) => handleServiceChange(e.target.value)}
                            className="p-2.5 rounded-xl border border-slate-200 outline-none bg-white text-sm"
                        >
                            <option value="">Choisir un service...</option>
                            {services.map((s) => (
                                <option key={s.id} value={s.id}>{s.name} ({s.durationMinutes} min)</option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col gap-1.5">
                        <label className="text-[10px] font-bold text-studio-muted uppercase">Note</label>
                        <input
                            type="text"
                            placeholder="Ex: Cheveux épais, café noir..."
                            value={note}
                            onChange={(e) => setNote(e.target.value)}
                            className="p-2.5 rounded-xl border border-slate-200 outline-none bg-white text-sm text-slate-800"
                        />
                    </div>
                </div>

                {/* ACTIONS */}
                <div className="flex justify-between items-center mt-2">
                    {/* Alerte courte si client/service non sélectionné */}
                    {(!selectedCustomer || !serviceId) && (
                        <div className="text-[12px] text-yellow-600 flex items-center gap-2">
                            <AlertTriangle size={14} /> Veuillez sélectionner un client et un service
                        </div>
                    )}
                    {initialData?.id && (
                        <button
                            type="button"
                            onClick={handleDelete}
                            className="text-red-500 text-[11px] font-bold flex items-center gap-1.5 hover:opacity-80 transition-opacity"
                        >
                            <Trash2 size={14} /> SUPPRIMER
                        </button>
                    )}
                    <div className="flex gap-2 ml-auto">
                        <button type="button" onClick={onClose} className="px-5 py-2 text-slate-400 font-bold text-sm">
                            ANNULER
                        </button>
                        <button
                            type="submit"
                            disabled={isFormInvalid || isSaving}
                            className="px-7 py-3 bg-studio-primary text-white rounded-full font-bold text-sm flex items-center gap-2 shadow-lg shadow-studio-primary/20 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {isSaving ? "..." : <><Zap size={14} /> CONFIRMER</>}
                        </button>
                    </div>
                </div>
            </form>
        </BaseModal>
    )
}
